        if (updatedTask.subtasks) {
            // Get existing subtask IDs for this task
            const { data: currentSubtasks } = await supabase
                .from('subtasks')
                .select('id')
                .eq('task_id', updatedTask.id);

            const currentIds = new Set<string>((currentSubtasks || []).map((s: any) => s.id));
