        // 2. Move incomplete tasks (tasks in this sprint that are NOT in Done column)
        // Finding incomplete tasks requires complex logic (knowing which columns are 'Done'). 
        // Ideally done via RPC. For frontend-heavy logic:
        // We'll trust the component passed the correct logic or we call an RPC.
        // Let's implement a simple logic: Move ALL tasks from this sprint to new sprint or null.
        // NOTE: Real implementation should filter only *incomplete* tasks. 
        // Assuming the UI logic handles "what to move" is hard here without task list.
        // Let's rely on an RPC if possible, or naive update.

        // Naive update: Update ALL tasks in the sprint to the new target. 
        // (In a real app, completed tasks should probably stay associated with the completed sprint for history, 
        // and only incomplete ones move. This requires a `sprint_history` table or `completed_sprint_id` field.
        // For this MVP, we will just update the sprint_id, essentially moving them.)
        const { error: taskError } = await supabase.from('tasks')
            .update({ sprint_id: moveToSprintId })
            .eq('sprint_id', sprintId);
            // .neq('status', 'Done') -- Can't easily filter by column title here without joining

        if (taskError) throw taskError;
    },

    addFilterSegment: async (projectId: string, name: string, filters: any, creatorId: string) => {
        const { error } = await supabase.from('filter_segments').insert({
            project_id: projectId === 'global' ? null : projectId, // Handle global views
