    getInviteLinksForProject: async (projectId: string) => {
        const { data, error } = await supabase.from('project_invite_links').select('*').eq('project_id', projectId);
        if (error) throw error;
        return data as ProjectInviteLink[];
    },

    createInviteLink: async (projectId: string, creatorId: string, role: string, expiresInDays: number | null) => {
        const token = crypto.randomUUID();
        let expiresAt = null;
        if (expiresInDays) {
            const date = new Date();
            date.setDate(date.getDate() + expiresInDays);
            expiresAt = date.toISOString();
        }

        const { error } = await supabase.from('project_invite_links').insert({
            project_id: projectId,
            created_by: creatorId,
            role,
            token,
            expires_at: expiresAt,
            access_type: 'open'
        });
        if (error) throw error;
    },

    updateInviteLink: async (linkId: string, updates: Partial<ProjectInviteLink>) => {
        const { error } = await supabase.from('project_invite_links').update(updates).eq('id', linkId);
