    acceptInvite: async (token: string) => {
        // 1. Get the invite link
        const { data: link, error: linkError } = await supabase.from('project_invite_links').select('*').eq('token', token).single();
        if (linkError || !link) throw new Error("Invalid invite link");

        // 2. Check expiration
        if (link.expires_at && new Date(link.expires_at) < new Date()) {
            throw new Error("Invite link has expired");
        }
        if (!link.is_active) {
            throw new Error("Invite link is no longer active");
        }

        // 3. Get current user
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) throw new Error("User not authenticated");

        // 4. Add user to project members (append to array)
        // First get current members to avoid duplicates
        const { data: project, error: projectError } = await supabase.from('projects').select('members, name, id').eq('id', link.project_id).single();
        if (projectError) throw projectError;

        const currentMembers: string[] = project.members || [];
        if (!currentMembers.includes(user.id)) {
            const { error: updateError } = await supabase.from('projects')
                .update({ members: [...currentMembers, user.id] })
                .eq('id', link.project_id);
            if (updateError) throw updateError;
        }

        // 5. Increment usage count
        await supabase.from('project_invite_links').update({ current_uses: (link.current_uses || 0) + 1 }).eq('id', link.id);

        return project;
    }
  },
  realtime: {
    isConfigured: () => {
        // Simple check if supabase is initialized (it throws in services/supabase.ts if not)
        return true; 
    },
    getPresenceChannel: () => {
        return supabase.channel('online-users');
    },
    removeChannel: (channel: RealtimeChannel) => {
        supabase.removeChannel(channel);
    }
  }
};
