      const handleMeetingChange = (payload: any) => {
          const { eventType, new: newRecord, old: oldRecord } = payload;

          setState(prevState => {
              const newState = { ...prevState };
              const projectIdsToUpdate = new Set<string>();
              if (newRecord) projectIdsToUpdate.add(newRecord.project_id);
              if (oldRecord) projectIdsToUpdate.add(oldRecord.project_id);

              projectIdsToUpdate.forEach(pid => {
                  if (newState.projects[pid]) {
                      // We need to re-fetch or smartly update. 
                      // Given the complexity of filtering left_at locally from a stream, 
                      // and the low volume of meeting join/leaves, simplistic list management is safer.

                      let participants = newState.projects[pid].activeMeetingParticipants || [];

                      if (eventType === 'INSERT') {
                          // Check if already exists (dedupe)
                          if (!participants.some(p => p.id === newRecord.id)) {
                              participants.push({
                                  id: newRecord.id,
                                  projectId: newRecord.project_id,
                                  userId: newRecord.user_id,
                                  joinedAt: newRecord.joined_at,
                                  leftAt: newRecord.left_at
                              });
                          }
                      } else if (eventType === 'UPDATE') {
                          if (newRecord.left_at) {
                              // Remove from active list
                              participants = participants.filter(p => p.id !== newRecord.id);
                          } else {
                              // Update
                              participants = participants.map(p => p.id === newRecord.id ? {
                                  ...p,
                                  leftAt: newRecord.left_at
                              } : p);
                          }
                      }

                      newState.projects[pid] = {
                          ...newState.projects[pid],
                          activeMeetingParticipants: participants
                      };
                  }
              });

              return newState;
          });
      };

      const subscription = api.data.subscribeToMeetingUpdates([], handleMeetingChange);
      return () => {
          subscription.unsubscribe();
      };
  }, [session, userId]);


