  const completeSprint = useCallback(async (sprintId: string, moveToSprintId: string | null) => {
    await api.data.completeSprint(sprintId, moveToSprintId);
    await fetchData();
  }, [fetchData]);

  // Filter Segment Management
  const addFilterSegment = useCallback(async (projectId: string, name: string, filters: FilterSegment['filters'], creatorId: string) => {
    await api.data.addFilterSegment(projectId, name, filters, creatorId);
    await fetchData();
  }, [fetchData]);

  const updateFilterSegment = useCallback(async (segmentId: string, updates: { name?: string, filters?: FilterSegment['filters'] }) => {
    await api.data.updateFilterSegment(segmentId, updates);
    await fetchData();
  }, [fetchData]);

  const deleteFilterSegment = useCallback(async (segmentId: string) => {
    await api.data.deleteFilterSegment(segmentId);
    await fetchData();
  }, [fetchData]);

  // Google Meet Wrappers
  const updateProjectMeetLink = useCallback(async (projectId: string, link: string) => {
      await api.data.saveProjectMeetLink(projectId, link);
      // Optimistic update
      setState(prev => ({
          ...prev,
          projects: {
              ...prev.projects,
              [projectId]: { ...prev.projects[projectId], googleMeetLink: link }
          }
      }));
  }, []);

  const joinMeeting = useCallback(async (projectId: string) => {
      if (!currentUser) return;
      await api.data.joinProjectMeeting(projectId, currentUser.id);
      // No manual fetch needed, realtime will handle it
  }, [currentUser]);

  const leaveMeeting = useCallback(async (projectId: string) => {
      if (!currentUser) return;
      await api.data.leaveProjectMeeting(currentUser.id);
      // No manual fetch needed, realtime will handle it
  }, [currentUser]);


  return { 
      state, loading, fetchData, onDragEnd, updateTask, addSubtasks, addComment, addTask, addAiTask, 
      deleteTask, addColumn, deleteColumn, addProject, addProjectFromPlan, deleteProject, updateUserProfile, 
      updateProjectMembers, sendChatMessage, addProjectLink, deleteProjectLink, addBug, updateBug, deleteBug, 
      addBugsBatch, deleteBugsBatch, addTasksBatch, addSprint, updateSprint, deleteSprint, bulkUpdateTaskSprint, 
      completeSprint, addFilterSegment, updateFilterSegment, deleteFilterSegment, 
      updateProjectMeetLink, joinMeeting, leaveMeeting 
  };
};

