```typescript
import React, { useMemo } from 'react';
import { CopyIcon, CheckIcon } from './Icons';

interface JsonSyntaxHighlighterProps {
  data: string | object;
  className?: string;
}

export const JsonSyntaxHighlighter: React.FC<JsonSyntaxHighlighterProps> = ({ data, className = '' }) => {
  const [copied, setCopied] = React.useState(false);

  const { jsonString, lines } = useMemo(() => {
    let obj = data;
    if (typeof data === 'string') {
      try {
        obj = JSON.parse(data);
      } catch (e) {
        // If parsing fails, just treat as string
        obj = data;
      }
    }
    const str = JSON.stringify(obj, null, 2);
    return { jsonString: str, lines: str.split('\n') };
  }, [data]);

  const handleCopy = (e: React.MouseEvent) => {
    e.stopPropagation();
    navigator.clipboard.writeText(jsonString);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const renderLine = (line: string) => {
    // Basic syntax highlighting regex
    // Matches: keys, strings, numbers, booleans, null
    const parts = line.split(/(".*?"|:|\d+|true|false|null)/g).filter(Boolean);

    return parts.map((part, i) => {
        if (part === ':') return <span key={i} className="text-gray-500">{part}</span>;
        if (part.startsWith('"')) {
            if (line.trim().startsWith(part) && line.includes(':')) {
                // It's a key
                return <span key={i} className="text-blue-300">{part}</span>;
            }
            // It's a string value
            return <span key={i} className="text-green-300">{part}</span>;
        }
        if (!isNaN(Number(part))) return <span key={i} className="text-orange-300">{part}</span>;
        if (['true', 'false'].includes(part)) return <span key={i} className="text-purple-300">{part}</span>;
        if (part === 'null') return <span key={i} className="text-gray-400">{part}</span>;

        return <span key={i} className="text-gray-300">{part}</span>;
    });
  };

  return (
    <div className={`relative group bg-[#0D1117] rounded-md border border-gray-800 overflow-hidden text-xs font-mono ${className}`}>
        <button
            onClick={handleCopy}
            className="absolute top-2 right-2 p-1.5 rounded bg-gray-800 text-gray-400 opacity-0 group-hover:opacity-100 transition-opacity hover:text-white z-10"
            title="Copy JSON"
        >
            {copied ? <CheckIcon className="w-3.5 h-3.5 text-green-500" /> : <CopyIcon className="w-3.5 h-3.5" />}
        </button>
        <div className="overflow-x-auto custom-scrollbar p-3">
            <table className="w-full border-collapse">
                <tbody>
                    {lines.map((line, index) => (
                        <tr key={index} className="hover:bg-white/5 transition-colors">
                            <td className="pr-4 text-right text-gray-600 select-none w-8 align-top">
                                {index + 1}
                            </td>
                            <td className="whitespace-pre align-top">
                                {renderLine(line)}
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    </div>
  );
};
